```tsx
"use client";

import React, { useState, useCallback, useRef, useEffect } from "react";
import { useStorage, useMutation } from "@liveblocks/react";
import { LiveObject } from "@liveblocks/client";

type MindMapNode = {
  id: string;
  label: string;
  x: number;
  y: number;
  parentId: string | null;
};

export function MindMap() {
  const nodes = useStorage((root) => {
    const map = root.nodes;
    if (!map) return [] as MindMapNode[];
    const result: MindMapNode[] = [];
    const keys = Array.from(map.keys());
    for (const key of keys) {
      const node = map.get(key);
      if (node) {
        result.push({
          id: node.id,
          label: node.label,
          x: node.x,
          y: node.y,
          parentId: node.parentId,
        });
      }
    }
    return result;
  });

  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [draggingNodeId, setDraggingNodeId] = useState<string | null>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const dragOffsetRef = useRef({ x: 0, y: 0 });
  const selectedNodeIdRef = useRef<string | null>(null);
  const lastDragUpdateRef = useRef(0);

  selectedNodeIdRef.current = selectedNodeId;

  // Add a new node
  const addNode = useMutation(({ storage }, x: number, y: number) => {
    const nodesMap = storage.get("nodes");
    const id = `node-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;

    let parentId: string | null = null;
    const currentSelectedId = selectedNodeIdRef.current;
    if (currentSelectedId) {
      parentId = currentSelectedId;
    } else {
      // Find root node
      const keys = Array.from(nodesMap.keys());
      for (const key of keys) {
        const node = nodesMap.get(key);
        if (node && node.get("parentId") === null) {
          parentId = node.get("id");
          break;
        }
      }
    }

    const newNode = new LiveObject<MindMapNode>({
      id,
      label: "New Node",
      x,
      y,
      parentId,
    });

    nodesMap.set(id, newNode);
    setSelectedNodeId(id);
  }, []);

  // Update node position
  const updateNodePosition = useMutation(({ storage }, id: string, x: number, y: number) => {
    const nodesMap = storage.get("nodes");
    const node = nodesMap.get(id);
    if (node) {
      node.update({ x, y });
    }
  }, []);

  // Rename node
  const renameNode = useMutation(({ storage }, id: string, label: string) => {
    const nodesMap = storage.get("nodes");
    const node = nodesMap.get(id);
    if (node) {
      node.update({ label });
    }
  }, []);

  // Delete node and descendants
  const deleteNode = useMutation(({ storage }, id: string) => {
    const nodesMap = storage.get("nodes");

    // Collect all descendants
    const toDelete = new Set<string>();
    const collectDescendants = (parentId: string) => {
      toDelete.add(parentId);
      const keys = Array.from(nodesMap.keys());
      for (const key of keys) {
        const node = nodesMap.get(key);
        if (node && node.get("parentId") === parentId) {
          collectDescendants(node.get("id")!);
        }
      }
    };
    collectDescendants(id);

    // Delete all collected nodes
    for (const nodeId of toDelete) {
      nodesMap.delete(nodeId);
    }

    setSelectedNodeId(null);
  }, []);

  // Handle SVG mouse down (create new node)
  const handleSvgMouseDown = useCallback((e: React.MouseEvent<SVGSVGElement>) => {
    const target = e.target as Element;
    // Only create node if clicking on the SVG itself (not on nodes or edges)
    if (target.tagName === "svg" || target === svgRef.current) {
      const svgRect = svgRef.current!.getBoundingClientRect();
      const x = e.clientX - svgRect.left;
      const y = e.clientY - svgRect.top;
      addNode(x, y);
    }
  }, [addNode]);

  // Handle node mouse down (start drag, select)
  const handleNodeMouseDown = useCallback((e: React.MouseEvent, nodeId: string) => {
    e.stopPropagation();
    e.preventDefault();

    setSelectedNodeId(nodeId);
    setDraggingNodeId(nodeId);

    const node = nodes.find(n => n.id === nodeId);
    if (node && svgRef.current) {
      const svgRect = svgRef.current.getBoundingClientRect();
      dragOffsetRef.current = {
        x: e.clientX - svgRect.left - node.x,
        y: e.clientY - svgRect.top - node.y,
      };
    }
  }, [nodes]);

  // Handle mouse move (drag)
  const handleMouseMove = useCallback((e: React.MouseEvent<SVGSVGElement>) => {
    if (draggingNodeId && svgRef.current) {
      const now = Date.now();
      if (now - lastDragUpdateRef.current < 16) {
        return; // Throttle to ~60fps
      }
      lastDragUpdateRef.current = now;

      const svgRect = svgRef.current.getBoundingClientRect();
      const x = e.clientX - svgRect.left - dragOffsetRef.current.x;
      const y = e.clientY - svgRect.top - dragOffsetRef.current.y;
      updateNodePosition(draggingNodeId, x, y);
    }
  }, [draggingNodeId, updateNodePosition]);

  // Handle mouse up (stop drag)
  const handleMouseUp = useCallback(() => {
    setDraggingNodeId(null);
  }, []);

  // Handle double click (rename)
  const handleNodeDoubleClick = useCallback((e: React.MouseEvent, nodeId: string) => {
    e.stopPropagation();
    const node = nodes.find(n => n.id === nodeId);
    if (node) {
      const newLabel = prompt("Enter new label:", node.label);
      if (newLabel !== null && newLabel !== undefined) {
        renameNode(nodeId, newLabel);
      }
    }
  }, [nodes, renameNode]);

  // Handle key down (delete)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.key === "Delete" || e.key === "Backspace") && selectedNodeId) {
        // Don't delete if user is typing in an input
        if ((e.target as HTMLElement).tagName === "INPUT" || (e.target as HTMLElement).tagName === "TEXTAREA") {
          return;
        }
        e.preventDefault();
        deleteNode(selectedNodeId);
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [selectedNodeId, deleteNode]);

  // Render edges
  const edges = nodes
    .filter(node => node.parentId !== null)
    .map(node => {
      const parent = nodes.find(n => n.id === node.parentId);
      if (!parent) return null;
      return {
        key: `edge-${parent.id}-${node.id}`,
        parentId: parent.id,
        childId: node.id,
        x1: parent.x,
        y1: parent.y,
        x2: node.x,
        y2: node.y,
      };
    })
    .filter(Boolean);

  return (
    <svg
      ref={svgRef}
      data-testid="mind-map-canvas"
      width="100%"
      height="100%"
      style={{ background: "#f8fafc", display: "block" }}
      onMouseDown={handleSvgMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
    >
      {/* Edges */}
      {edges.map(edge => (
        <line
          key={edge!.key}
          data-testid="mind-map-edge"
          data-parent-id={edge!.parentId}
          data-child-id={edge!.childId}
          x1={edge!.x1}
          y1={edge!.y1}
          x2={edge!.x2}
          y2={edge!.y2}
          stroke="#94a3b8"
          strokeWidth={2}
          style={{ pointerEvents: "none" }}
        />
      ))}

      {/* Nodes */}
      {nodes.map(node => (
        <g key={node.id}>
          <circle
            data-testid="mind-map-node"
            data-node-id={node.id}
            cx={node.x}
            cy={node.y}
            r={30}
            fill={node.id === selectedNodeId ? "#3b82f6" : "#ffffff"}
            stroke={node.id === selectedNodeId ? "#1d4ed8" : "#64748b"}
            strokeWidth={2}
            onMouseDown={(e) => handleNodeMouseDown(e, node.id)}
            onDoubleClick={(e) => handleNodeDoubleClick(e, node.id)}
            style={{ cursor: "pointer" }}
          />
          <text
            data-testid="mind-map-label"
            data-node-id={node.id}
            x={node.x}
            y={node.y}
            textAnchor="middle"
            dominantBaseline="central"
            fill={node.id === selectedNodeId ? "#ffffff" : "#1e293b"}
            fontSize={12}
            style={{ pointerEvents: "none", userSelect: "none" }}
          >
            {node.label}
          </text>
        </g>
      ))}
    </svg>
  );
}
```

